MAP
  NAME "TURKIYE_3D_SYSTEM"
  STATUS ON
  SIZE 256 256
  UNITS DD
  SHAPEPATH "/data"
  IMAGECOLOR 0 0 0

  PROJECTION
    "init=epsg:4326"
  END

  OUTPUTFORMAT
    NAME "jpeg"
    DRIVER "GDAL/JPEG"
    MIMETYPE "image/jpeg"
    IMAGEMODE RGB
    EXTENSION "jpg"
  END

  WEB
    METADATA
      "wms_title"                                   "MapServer WMS Multi-Service"
      "wms_enable_request"                          "*"
      "wms_srs"                                     "EPSG:4326"
      "wms_allow_getmap_without_styles"             "true"
      "ows_enable_request"                          "*"
      "ows_srs"                                     "EPSG:4326"
      "ows_http_header_Access-Control-Allow-Origin" "*"
      "ows_http_header_Access-Control-Allow-Methods" "GET,POST,OPTIONS"
      "ows_http_header_Access-Control-Allow-Headers" "X-Requested-With,Content-Type"
    END
  END

  # SADECE TEK KATMAN: HARİTANIN RENKLİ KUMAŞI (UYDU DOKUSU)
  LAYER
    NAME "uydu_dokusu"
    STATUS ON
    TYPE RASTER
    DATA "tiledNE2_med.tiff"

    PROJECTION
      "init=epsg:4326"
    END

    METADATA
      "wms_title"          "Natural Earth Dokusu"
      "wms_enable_request" "*"
      "wms_srs"            "EPSG:4326"
    END
  END
END